# Standard 2D DP approach
def edit_distance(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Base cases
    for i in range(m + 1):
        dp[i][0] = i  # delete all characters
    for j in range(n + 1):
        dp[0][j] = j  # insert all characters

    # Fill DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1]
            else:
                dp[i][j] = 1 + min(
                    dp[i-1][j],      # delete
                    dp[i][j-1],      # insert
                    dp[i-1][j-1]     # replace
                )

    return dp[m][n]

# Space-optimized version O(min(m,n)) space
def edit_distance_optimized(s1, s2):
    # Ensure s1 is shorter for space efficiency
    if len(s1) > len(s2):
        s1, s2 = s2, s1

    m, n = len(s1), len(s2)
    prev = list(range(n + 1))
    curr = [0] * (n + 1)

    for i in range(1, m + 1):
        curr[0] = i
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                curr[j] = prev[j-1]
            else:
                curr[j] = 1 + min(prev[j], curr[j-1], prev[j-1])
        prev, curr = curr, prev

    return prev[n]

# Test examples
print("Edit Distance Examples:")
print(f"'kitten' -> 'sitting': {edit_distance('kitten', 'sitting')}")
print(f"'Saturday' -> 'Sunday': {edit_distance('Saturday', 'Sunday')}")
print(f"Optimized result: {edit_distance_optimized('kitten', 'sitting')}")

# Trace operations
def edit_distance_with_trace(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(m + 1):
        dp[i][0] = i
    for j in range(n + 1):
        dp[0][j] = j

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1]
            else:
                dp[i][j] = 1 + min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1])

    # Backtrack to find operations
    i, j = m, n
    operations = []
    while i > 0 or j > 0:
        if i > 0 and j > 0 and s1[i-1] == s2[j-1]:
            operations.append(f"Match: '{s1[i-1]}'")
            i, j = i-1, j-1
        elif i > 0 and j > 0 and dp[i][j] == dp[i-1][j-1] + 1:
            operations.append(f"Replace '{s1[i-1]}' with '{s2[j-1]}'")
            i, j = i-1, j-1
        elif j > 0 and dp[i][j] == dp[i][j-1] + 1:
            operations.append(f"Insert '{s2[j-1]}'")
            j -= 1
        else:
            operations.append(f"Delete '{s1[i-1]}'")
            i -= 1

    return dp[m][n], list(reversed(operations))

cost, ops = edit_distance_with_trace("kitten", "sitting")
print(f"\nTransformation steps for 'kitten' -> 'sitting':")
for op in ops:
    print(f"  - {op}")
